#include <vector>
#include <string>
#include <algorithm>
#include <unordered_map>

std::vector<std::string> by_length(const std::vector<int>& arr) {
    std::vector<int> filtered;

    // Filter the array to include only numbers between 1 and 9
    for (int num : arr) {
        if (num >= 1 && num <= 9) {
            filtered.push_back(num);
        }
    }

    // If no valid numbers are found, return an empty vector
    if (filtered.empty()) {
        return {};
    }

    // Sort the filtered array
    std::sort(filtered.begin(), filtered.end());

    // Reverse the sorted array
    std::reverse(filtered.begin(), filtered.end());

    // Mapping of numbers to their corresponding names
    std::unordered_map<int, std::string> number_to_name = {
        {1, "One"}, {2, "Two"}, {3, "Three"}, {4, "Four"},
        {5, "Five"}, {6, "Six"}, {7, "Seven"}, {8, "Eight"}, {9, "Nine"}
    };

    // Replace each number with its corresponding name
    std::vector<std::string> result;
    for (int num : filtered) {
        result.push_back(number_to_name[num]);
    }

    return result;
}
